import {
  getFunctionalConsent,
  getMarketingConsent,
  getStatisticalConsent,
  checkConsent,
  ConsentType
} from "../../src/lib/consent";

const setConsent = (approved, denied) => {
  document.cookie = `CookieInformationConsent=%7B%22website_uuid%22%3A%22d116472a-33cc-480c-ae2b-b80c260850c6%22%2C%22timestamp%22%3A%222024-07-09T10%3A13%3A35.744Z%22%2C%22consent_url%22%3A%22https%3A%2F%2Fwww.maersk.com%2Flogistics-explained%22%2C%22consent_website%22%3A%22maersk.com%22%2C%22consent_domain%22%3A%22www.maersk.com%22%2C%22user_uid%22%3A%2251d026ad-04a6-43ad-93ca-07019df5af7b%22%2C%22consents_approved%22%3A%5B%22${approved}%22%5D%2C%22consents_denied%22%3A%5B${denied}%5D%2C%22user_agent%22%3A%22Mozilla%2F5.0%20%28Macintosh%3B%20Intel%20Mac%20OS%20X%2010_15_7%29%20AppleWebKit%2F537.36%20%28KHTML%2C%20like%20Gecko%29%20Chrome%2F126.0.0.0%20Safari%2F537.36%22%7D`;
};

describe("Cookie consent", () => {
  beforeEach(() => {
    document.cookie = "";
  });
  afterAll(() => {
    document.cookie = "";
  });

  test.each`
    title                                                           | approved                                                                     | denied                                                                       | functional | marketing | statistic | checkFor                   | customString
    ${"All approved"}                                               | ${["cookie_cat_functional", "cookie_cat_marketing", "cookie_cat_statistic"]} | ${[]}                                                                        | ${true}    | ${true}   | ${true}   | ${ConsentType.Marketing}   | ${undefined}
    ${"All denied"}                                                 | ${[]}                                                                        | ${["cookie_cat_functional", "cookie_cat_marketing", "cookie_cat_statistic"]} | ${false}   | ${false}  | ${false}  | ${ConsentType.Essential}   | ${undefined}
    ${"Only functional"}                                            | ${["cookie_cat_functional"]}                                                 | ${[]}                                                                        | ${true}    | ${false}  | ${false}  | ${ConsentType.Functional}  | ${undefined}
    ${"Only marketing"}                                             | ${["cookie_cat_marketing"]}                                                  | ${[]}                                                                        | ${false}   | ${true}   | ${false}  | ${ConsentType.Marketing}   | ${undefined}
    ${"Only statistic"}                                             | ${["cookie_cat_statistic"]}                                                  | ${[]}                                                                        | ${false}   | ${false}  | ${true}   | ${ConsentType.Statistical} | ${undefined}
    ${"No consent"}                                                 | ${[]}                                                                        | ${[]}                                                                        | ${false}   | ${false}  | ${false}  | ${ConsentType.Essential}   | ${undefined}
    ${"With a custom string that is junk"}                          | ${[]}                                                                        | ${[]}                                                                        | ${false}   | ${false}  | ${false}  | ${false}                   | ${"hello world"}
    ${"With a custom string without specifying approved or denied"} | ${[]}                                                                        | ${[]}                                                                        | ${false}   | ${false}  | ${false}  | ${false}                   | ${"cookie_cat_statistic"}
    ${"With a custom string that works"}                            | ${[]}                                                                        | ${[]}                                                                        | ${false}   | ${false}  | ${true}   | ${ConsentType.Statistical} | ${"consents_approved=[cookie_cat_statistic]"}
  `("$title", ({ approved, denied, functional, marketing, statistic, checkFor, customString }) => {
    setConsent(approved, denied);
    expect(getFunctionalConsent(customString)).toBe(functional);
    expect(getMarketingConsent(customString)).toBe(marketing);
    expect(getStatisticalConsent(customString)).toBe(statistic);
    if (checkFor) {
      expect(checkConsent(checkFor, customString)).toBe(true);
    } else {
      expect(checkConsent(checkFor, customString)).toBe(false);
    }
  });
});
